import { executeChild } from '@temporalio/workflow';

export async function DoubleWorkflow(n: number): Promise<number> {
  return n * 2;
}

export async function ParentSumWorkflow(numbers: number[]): Promise<number> {
  const doubledValues = await Promise.all(
    numbers.map((value) => executeChild(DoubleWorkflow, { args: [value] }))
  );

  return doubledValues.reduce((sum, value) => sum + value, 0);
}

import { NativeConnection, Worker } from '@temporalio/worker';

const TASK_QUEUE = 'child-workflow-ts';

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error('Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, or TEMPORAL_NAMESPACE environment variables.');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: TASK_QUEUE,
    workflowsPath: require.resolve('./workflows'),
  });

  await worker.run();
}

run().catch((error) => {
  console.error('Worker failed:', error);
  process.exit(1);
});

import { Client, Connection } from '@temporalio/client';

const TASK_QUEUE = 'child-workflow-ts';

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !namespace) {
    throw new Error('Missing TEMPORAL_ADDRESS, TEMPORAL_API_KEY, or TEMPORAL_NAMESPACE environment variables.');
  }

  if (!runId) {
    throw new Error('Missing ZEALT_RUN_ID environment variable.');
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const result = await client.workflow.execute('ParentSumWorkflow', {
    taskQueue: TASK_QUEUE,
    workflowId: `parent-wf-${runId}`,
    args: [[1, 2, 3]],
  });

  console.log(result);
}

run().catch((error) => {
  console.error('Client failed:', error);
  process.exit(1);
});

const { spawn } = require('child_process');

const workerProcess = spawn('npm', ['run', 'worker'], {
  stdio: 'inherit',
  env: process.env,
});

let shuttingDown = false;

const stopWorker = () => {
  if (shuttingDown) {
    return;
  }
  shuttingDown = true;
  workerProcess.kill('SIGTERM');
};

const runClient = () =>
  new Promise((resolve, reject) => {
    const clientProcess = spawn('npm', ['run', 'client'], {
      stdio: 'inherit',
      env: process.env,
    });

    clientProcess.on('exit', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`Client exited with code ${code}`));
      }
    });

    clientProcess.on('error', reject);
  });

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

(async () => {
  try {
    await delay(2000);
    await runClient();
    stopWorker();
  } catch (error) {
    console.error(error);
    stopWorker();
    process.exit(1);
  }
})();

process.on('SIGINT', () => {
  stopWorker();
  process.exit(1);
});

process.on('SIGTERM', () => {
  stopWorker();
  process.exit(1);
});
